/**
 * IVX Deployment State Machine + Evidence-First Report Validator.
 *
 * Owner spec (2026-07-11): a deployment may ONLY be reported as VERIFIED when
 * every required evidence field is present, real, and consistent. Anything
 * less is UNVERIFIED — never a narrative.
 *
 * Steps enforced here:
 *  - Step 5: the only allowed states, in the only allowed order. No skipping.
 *  - Step 4/6: the 18 required evidence fields; forbidden template values
 *    (AUTO-GENERATED, UNKNOWN, PENDING, PLACEHOLDER, MOCK, NARRATIVE,
 *    GENERATED, SIMULATED, ESTIMATED, ASSUMED) invalidate the report.
 *  - Step 7: health endpoint must be HTTP 200 AND the running commit SHA must
 *    equal the GitHub commit SHA (short-SHA prefix match allowed).
 *  - Step 8: failed production QA prevents VERIFIED.
 *  - Step 9: the report is rendered ONLY from evidence fields; missing values
 *    are printed as UNVERIFIED, never invented.
 *
 * Pure + deterministic (no I/O, network, or AI) so it is fully unit-testable.
 */

export const DEPLOYMENT_STATES = [
  'REPO_FROZEN',
  'CODE_CHANGED',
  'FILES_MODIFIED',
  'LOCAL_BUILD',
  'TESTS_PASSED',
  'COMMIT_CREATED',
  'PUSH_COMPLETED',
  'DEPLOY_STARTED',
  'DEPLOY_IN_PROGRESS',
  'DEPLOY_COMPLETED',
  'HEALTH_CHECK_OK',
  'PRODUCTION_VERIFIED',
] as const;

export type DeploymentMachineState = (typeof DEPLOYMENT_STATES)[number];

/**
 * Values that are NEVER valid inside an evidence field. A real deployment
 * report carries real tool output — these are unfilled template slots.
 */
export const FORBIDDEN_EVIDENCE_VALUES: readonly string[] = [
  'AUTO-GENERATED',
  'AUTO GENERATED',
  'AUTOGENERATED',
  'UNKNOWN',
  'PENDING',
  'PLACEHOLDER',
  'MOCK',
  'MOCKED',
  'NARRATIVE',
  'GENERATED',
  'SIMULATED',
  'ESTIMATED',
  'ASSUMED',
];

/** Whether a single evidence value is a forbidden template value. Pure. */
export function isForbiddenEvidenceValue(value: string | null | undefined): boolean {
  if (value === null || value === undefined) return false;
  const normalized = String(value).trim().replace(/^[[\s]+|[\]\s]+$/g, '').toUpperCase();
  if (normalized.length === 0) return false;
  return FORBIDDEN_EVIDENCE_VALUES.includes(normalized);
}

/**
 * Advance the deployment state machine by exactly one state. Skipping states
 * is a hard error — a deployment cannot claim PUSH_COMPLETED without
 * COMMIT_CREATED, or PRODUCTION_VERIFIED without HEALTH_CHECK_OK.
 * Pure — deterministic.
 */
export function advanceDeploymentState(
  current: DeploymentMachineState,
  next: DeploymentMachineState,
): { ok: boolean; error: string | null } {
  const currentIndex = DEPLOYMENT_STATES.indexOf(current);
  const nextIndex = DEPLOYMENT_STATES.indexOf(next);
  if (currentIndex === -1) return { ok: false, error: `unknown current state: ${current}` };
  if (nextIndex === -1) return { ok: false, error: `unknown next state: ${next}` };
  if (nextIndex !== currentIndex + 1) {
    return {
      ok: false,
