export function validateDeploymentEvidence(report: DeploymentEvidenceReport): DeploymentValidationResult {
  const missingFields: string[] = [];
  const forbiddenValues: string[] = [];
  const failures: string[] = [];

  for (const field of REQUIRED_FIELDS) {
    const value = report[field];
    if (value === null || value === undefined || String(value).trim().length === 0) {
      missingFields.push(field);
      continue;
    }
    if (typeof value === 'string' && isForbiddenEvidenceValue(value)) {
      forbiddenValues.push(`${field}=${String(value).trim()}`);
    }
  }

