    failures.push(`commitSha is not a real git SHA: ${report.commitSha}`);
  }
  if (!isRealCommitSha(report.runningCommitSha) && report.runningCommitSha !== null) {
    failures.push(`runningCommitSha is not a real git SHA: ${report.runningCommitSha}`);
  }
  if (report.httpStatus !== null && report.httpStatus !== 200) {
    failures.push(`health endpoint returned HTTP ${report.httpStatus} (200 required)`);
  }
  if (isRealCommitSha(report.commitSha) && isRealCommitSha(report.runningCommitSha)
    && !commitShasMatch(report.commitSha, report.runningCommitSha)) {
    failures.push(`running commit ${report.runningCommitSha} does not match GitHub commit ${report.commitSha}`);
  }
  if (report.pushStatus !== null && !/^(completed|pushed|success)$/i.test(report.pushStatus.trim())) {
    failures.push(`pushStatus is not a completed push: ${report.pushStatus}`);
  }
