    failures.push('production QA was not run');
  } else if (report.qaResult === 'FAIL') {
    failures.push('production QA failed');
  }

  const finalStatus: 'VERIFIED' | 'UNVERIFIED' =
    missingFields.length === 0 && forbiddenValues.length === 0 && failures.length === 0
      ? 'VERIFIED'
      : 'UNVERIFIED';

  return { finalStatus, missingFields, forbiddenValues, failures };
}

