  const forbidden = ['AUTO-GENERATED', 'UNKNOWN', 'PENDING', 'PLACEHOLDER', 'MOCK', 'NARRATIVE', 'GENERATED', 'SIMULATED', 'ESTIMATED', 'ASSUMED'];

  test.each(forbidden)('Deployment ID: %s is a placeholder violation', (value) => {
